export const CMS1500_TEMPLATE_BASE64 = CHUNKS.join("");

/**
 * Decodes the embedded CMS-1500 PDF template to a Uint8Array.
 * This is the actual PDF template bundled with the package — no fetch or file copy needed.
 */
export function getEmbeddedTemplate(): Uint8Array {
  const binaryString = atob(CMS1500_TEMPLATE_BASE64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}
